def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import math
    THRESH = 0.01  # 1% change threshold to avoid floating point issues

    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)
    slide_orig = prs_orig.slides[1]  # slide_number is 2, index 1-based
    slide_mod = prs_mod.slides[1]
    # Get all pictures on both slides
    orig_pics = [(shape.left, shape.top, shape.width, shape.height) for shape in slide_orig.shapes if shape.shape_type == 13]
    mod_pics = [(shape.left, shape.top, shape.width, shape.height) for shape in slide_mod.shapes if shape.shape_type == 13]
    # Assume images relate by order
    changed = False
    min_pics = min(len(orig_pics), len(mod_pics))
    for i in range(min_pics):
        l0, t0, w0, h0 = orig_pics[i]
        l1, t1, w1, h1 = mod_pics[i]
        if abs(w0 - w1) > w0 * THRESH or abs(h0 - h1) > h0 * THRESH:
            changed = True
            break
    if changed:
        return ("An image on slide 2 was resized.", 1.0)
    else:
        if len(orig_pics) == 0 and len(mod_pics) == 0:
            return ("No images on slide 2 to resize.", 1.0)
        return ("No image on slide 2 was resized compared to original.", 0.0)

