def compute_score() -> tuple[str, float]:
    # Check that we didn't add extraneous content to slide 2 aside from the required bullet point

    target_bullet = "All three axes intersect at the aircraft's center of gravity"

    # Compare slide content, allowing for the added bullet point
    original_slide = None
    modified_slide = None

    from pptx import Presentation
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)

    if len(list(prs_orig.slides)) < 2 or len(list(prs_mod.slides)) < 2:
        return ("Slide 2 not found in one of the presentations.", 0.0)

    original_slide = list(prs_orig.slides)[1]  # Slide 2
    modified_slide = list(prs_mod.slides)[1]   # Slide 2

    # Get text content from both slides
    orig_texts = []
    mod_texts = []

    for shape in original_slide.shapes:
        if shape.has_text_frame:
            for para in shape.text_frame.paragraphs:
                text = para.text.strip()
                if text:
                    orig_texts.append(text)

    for shape in modified_slide.shapes:
        if shape.has_text_frame:
            for para in shape.text_frame.paragraphs:
                text = para.text.strip()
                if text:
                    mod_texts.append(text)

    # Remove the target bullet from modified texts for comparison
    mod_texts_cleaned = [t for t in mod_texts if t != target_bullet]

    # Check if all original texts are still present
    missing_texts = []
    for orig_text in orig_texts:
        if orig_text not in mod_texts_cleaned:
            missing_texts.append(orig_text)

    # Check for unexpected additions (beyond the target bullet)
    extra_texts = []
    for mod_text in mod_texts_cleaned:
        if mod_text not in orig_texts:
            extra_texts.append(mod_text)

    if missing_texts or extra_texts:
        return (f"Extraneous changes detected. Missing: {missing_texts}, Extra: {extra_texts}", 0.0)
    else:
        return ("No extraneous content changes on slide 2.", 1.0)

def compute_score() -> tuple[str, float]:
    # Check that no unwarranted changes were made elsewhere in the presentation

    from pptx import Presentation
    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)

    orig_slides = list(prs_orig.slides)
    mod_slides = list(prs_mod.slides)

    if len(orig_slides) != len(mod_slides):
        return ("Number of slides changed unexpectedly.", 0.0)

    # Check all slides except slide 2 (index 1)
    for i, (orig_slide, mod_slide) in enumerate(zip(orig_slides, mod_slides)):
        if i == 1:  # Skip slide 2 (index 1) as it should have changes
            continue

        # Get text content from both slides
        orig_texts = []
        mod_texts = []

        for shape in orig_slide.shapes:
            if shape.has_text_frame:
                for para in shape.text_frame.paragraphs:
                    text = para.text.strip()
                    if text:
                        orig_texts.append(text)

        for shape in mod_slide.shapes:
            if shape.has_text_frame:
                for para in shape.text_frame.paragraphs:
                    text = para.text.strip()
                    if text:
                        mod_texts.append(text)

        if set(orig_texts) != set(mod_texts):
            return (f"Unexpected changes found on slide {i+1}.", 0.0)

    return ("No unwarranted changes elsewhere in presentation.", 1.0)
